const { PAGE_MEMBERS } = require('../../constants/page');
const {
  PAGE_HOOKS_REGEX,
  VIEW_REGEX,
  STYLES_REGEX,
} = require('../../constants/regexs');

/**
 * @typedef { keyof PAGE_MEMBERS } PageMemberType
 */

/**
 * Looks for the page member of the file path received.
 * The page member options are:
 * - PAGE_MEMBERS.view
 * - PAGE_MEMBERS.styles
 * - PAGE_MEMBERS.hooks
 * @param { string } filePath - File path to analize
 * @returns { PageMemberType | null } Page member found or empty string
 *
 * @example
 * getFilePageMember('product/[id].ts') => PAGE_MEMBERS.view
 * getFilePageMember('home.scss') => PAGE_MEMBERS.styles
 * getFilePageMember('help/index.hooks.server.ts') => PAGE_MEMBERS.hooks
 * getFilePageMember('product/data.json') => null
 */
const getFilePageMember = (filePath) => {
  if (PAGE_HOOKS_REGEX.test(filePath)) {
    return PAGE_MEMBERS.hooks;
  }

  if (VIEW_REGEX.test(filePath)) {
    return PAGE_MEMBERS.view;
  }

  if (STYLES_REGEX.test(filePath)) {
    return PAGE_MEMBERS.styles;
  }

  return null;
};

module.exports = { getFilePageMember };
